import { cacheTag } from 'next/cache';

export type Post = {
  id: number;
  title: string;
  content: string;
};

// In-memory store (replace with a database in production)
const posts: Post[] = [
  { id: 1, title: 'Hello World', content: 'This is the first post.' },
  { id: 2, title: 'Getting Started', content: 'Welcome to the blog!' },
];

let nextId = 3;

export async function getPosts(): Promise<Post[]> {
  'use cache';
  cacheTag('posts');
  return posts;
}

export function createPostInStore(title: string, content: string): Post {
  const post: Post = { id: nextId++, title, content };
  posts.push(post);
  return post;
}

'use server';

import { updateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { createPostInStore } from '@/app/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || typeof title !== 'string' || title.trim().length === 0) {
    throw new Error('Title is required');
  }

  if (!content || typeof content !== 'string' || content.trim().length === 0) {
    throw new Error('Content is required');
  }

  createPostInStore(title.trim(), content.trim());

  // Immediately expire the 'posts' cache tag.
  // The next page load will fetch fresh data — no stale content is served.
  updateTag('posts');

  redirect('/');
}

import { Suspense } from 'react';
import { getPosts } from '@/app/lib/posts';
import { createPost } from '@/app/actions';

async function PostsList() {
  const posts = await getPosts();

  return (
    <ul>
      {posts.map((post) => (
        <li key={post.id}>
          <h2>{post.title}</h2>
          <p>{post.content}</p>
        </li>
      ))}
    </ul>
  );
}

function PostsListFallback() {
  return <p>Loading posts...</p>;
}

function CreatePostForm() {
  return (
    <form action={createPost}>
      <div>
        <label htmlFor="title">Title</label>
        <input id="title" name="title" type="text" required />
      </div>
      <div>
        <label htmlFor="content">Content</label>
        <textarea id="content" name="content" required />
      </div>
      <button type="submit">Create Post</button>
    </form>
  );
}

export default function Home() {
  return (
    <main>
      <h1>Posts</h1>

      <Suspense fallback={<PostsListFallback />}>
        <PostsList />
      </Suspense>

      <hr />

      <section>
        <h2>Create a New Post</h2>
        <CreatePostForm />
      </section>
    </main>
  );
}

